package ru.memearena.vote.application; import org.springframework.dao.DataIntegrityViolationException; import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ru.memearena.error.*; import ru.memearena.meme.domain.*; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.ranking.domain.EloRatingCalculator; import ru.memearena.user.application.UserProfileService; import ru.memearena.user.infrastructure.UserProfileRepository; import ru.memearena.vote.api.*; import ru.memearena.vote.domain.Vote; import ru.memearena.vote.infrastructure.VoteRepository; import java.time.*; import java.util.*; import java.util.function.Function; import java.util.stream.Collectors;
@Service public class VoteService { private final VoteRepository votes; private final MemeRepository memes; private final UserProfileService users; private final UserProfileRepository userRepo; private final Clock clock; public VoteService(VoteRepository votes,MemeRepository memes,UserProfileService users,UserProfileRepository userRepo,Clock clock){this.votes=votes;this.memes=memes;this.users=users;this.userRepo=userRepo;this.clock=clock;} @Transactional public SubmitVoteResponse submit(UUID userId,UUID leftId,UUID rightId,UUID winnerId){ if(leftId.equals(rightId)) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.INVALID_BATTLE_PAIR,"Battle pair must contain two different memes"); if(!winnerId.equals(leftId)&&!winnerId.equals(rightId)) throw new ApiException(HttpStatus.BAD_REQUEST,ErrorCode.INVALID_WINNER,"Winner must be in pair"); var user=users.get(userId); String pair=Vote.pairKey(leftId,rightId); if(votes.existsByUserIdAndPairKey(userId,pair)) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.PAIR_ALREADY_VOTED,"Pair already voted"); // Locks are acquired in UUID order to reduce deadlock risk between concurrent votes for the same memes.
 List<UUID> ordered=List.of(leftId,rightId).stream().sorted(Comparator.comparing(UUID::toString)).toList(); var locked=memes.lockByIdInOrder(ordered); if(locked.size()!=2) throw new ApiException(HttpStatus.NOT_FOUND,ErrorCode.MEME_NOT_FOUND,"Meme not found"); Map<UUID,Meme> byId=locked.stream().collect(Collectors.toMap(Meme::getId,Function.identity())); Meme winner=byId.get(winnerId); Meme loser=byId.get(winnerId.equals(leftId)?rightId:leftId); if(winner.getModerationStatus()!=ModerationStatus.APPROVED||loser.getModerationStatus()!=ModerationStatus.APPROVED) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.MEME_NOT_AVAILABLE,"Meme is not available"); int wrb=winner.getRating(), lrb=loser.getRating(); var r=EloRatingCalculator.calculate(wrb,lrb); Instant now=Instant.now(clock); winner.win(r.winnerRatingAfter(),now); loser.lose(r.loserRatingAfter(),now); user.incrementVotes(now); Vote vote=new Vote(UUID.randomUUID(),userId,leftId,rightId,winnerId,loser.getId(),pair,wrb,r.winnerRatingAfter(),lrb,r.loserRatingAfter(),now); try{votes.saveAndFlush(vote);}catch(DataIntegrityViolationException e){throw new ApiException(HttpStatus.CONFLICT,ErrorCode.PAIR_ALREADY_VOTED,"Pair already voted");} userRepo.save(user); return new SubmitVoteResponse(vote.getId(),new VoteRatingChangeResponse(winnerId,wrb,r.winnerRatingAfter()),new VoteRatingChangeResponse(loser.getId(),lrb,r.loserRatingAfter()),user.getVotesCount(),user.status()); } }
